import{_ as e,c as s,o as i,aj as n}from"./chunks/framework.VtnL2jmu.js";const f=JSON.parse('{"title":"fzf (fuzzy finder) 空间传送门","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/fzf (fuzzy finder) 空间传送门.md","filePath":"Linux/fzf (fuzzy finder) 空间传送门.md"}'),r={name:"Linux/fzf (fuzzy finder) 空间传送门.md"};function d(t,a,o,c,l,p){return i(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="fzf-fuzzy-finder-空间传送门" tabindex="-1"><strong>fzf</strong> (<em>fuzzy finder</em>) 空间传送门 <a class="header-anchor" href="#fzf-fuzzy-finder-空间传送门" aria-label="Permalink to “fzf (fuzzy finder) 空间传送门”">​</a></h1><p>在 Linux 开发中，我们经常要面对成千上万个文件、几百条历史命令，或者几十个正在运行的进程。<strong>fzf</strong> 的作用就是通过<strong>模糊搜索</strong>，让你在一瞬间从海量信息中抓取到你想要的那一个。</p><hr><h3 id="_1-核心魅力-什么是-模糊搜索" tabindex="-1">1. 核心魅力：什么是“模糊搜索”？ <a class="header-anchor" href="#_1-核心魅力-什么是-模糊搜索" aria-label="Permalink to “1. 核心魅力：什么是“模糊搜索”？”">​</a></h3><p>传统的搜索需要你完全拼对单词（比如 <code>grep &quot;UserService&quot;</code>），而 <code>fzf</code> 允许你乱序、缩写搜索。</p><p>比如你想找 <code>src/main/java/com/muzi/service/UserService.java</code>：</p><p>你只需要输入 <code>smjsUser</code>，<code>fzf</code> 就能帮你把它定位出来。</p><hr><h3 id="_2-安装与集成-关键一步" tabindex="-1">2. 安装与集成（关键一步） <a class="header-anchor" href="#_2-安装与集成-关键一步" aria-label="Permalink to “2. 安装与集成（关键一步）”">​</a></h3><p><code>fzf</code> 不仅仅是一个工具，它更像是一个插件。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 1. 安装</span></span>
<span class="line"><span>sudo apt install fzf</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 2. 启用键盘快捷键绑定（这一步是灵魂！）</span></span>
<span class="line"><span># 不同的发行版路径不同，通常运行这个脚本即可：</span></span>
<span class="line"><span>source /usr/share/doc/fzf/examples/key-bindings.bash &amp;&amp; source ~/.bashrc</span></span></code></pre></div><hr><h3 id="_3-三大-神级-快捷键-开发必会" tabindex="-1">3. 三大“神级”快捷键（开发必会） <a class="header-anchor" href="#_3-三大-神级-快捷键-开发必会" aria-label="Permalink to “3. 三大“神级”快捷键（开发必会）”">​</a></h3><p>安装并配置好后，你会解锁三个逆天的操作：</p><h4 id="_1-ctrl-r-历史命令-救命草" tabindex="-1">① <code>CTRL + R</code>：历史命令“救命草” <a class="header-anchor" href="#_1-ctrl-r-历史命令-救命草" aria-label="Permalink to “① CTRL + R：历史命令“救命草””">​</a></h4><p>这是最常用的场景。以前你可能要不停地按向上箭头，或者 <code>history | grep &quot;mvn&quot;</code>。</p><p>现在：按 <code>CTRL + R</code>，输入 <code>mvn run</code> 或者 <code>login</code>，<code>fzf</code> 会立即列出所有匹配的历史命令，回车即用。</p><h4 id="_2-ctrl-t-快速找文件" tabindex="-1">② <code>CTRL + T</code>：快速找文件 <a class="header-anchor" href="#_2-ctrl-t-快速找文件" aria-label="Permalink to “② CTRL + T：快速找文件”">​</a></h4><p>在终端想打开某个深层目录的文件？</p><p>输入 <code>vim </code> 然后按 <code>CTRL + T</code>，直接模糊搜索文件名，选中后文件名会自动补全到 <code>vim</code> 后面。</p><h4 id="_3-alt-c-快速切目录" tabindex="-1">③ <code>ALT + C</code>：快速切目录 <a class="header-anchor" href="#_3-alt-c-快速切目录" aria-label="Permalink to “③ ALT + C：快速切目录”">​</a></h4><p>想去某个文件夹？按 <code>ALT + C</code>，输入文件夹名的几个字母，瞬间闪现过去。</p><hr><h3 id="_4-配合你的-spring-boot-开发流" tabindex="-1">4. 配合你的 Spring Boot 开发流 <a class="header-anchor" href="#_4-配合你的-spring-boot-开发流" aria-label="Permalink to “4. 配合你的 Spring Boot 开发流”">​</a></h3><h4 id="场景一-快速查看日志" tabindex="-1">场景一：快速查看日志 <a class="header-anchor" href="#场景一-快速查看日志" aria-label="Permalink to “场景一：快速查看日志”">​</a></h4><p>如果你的日志文件很多，或者你想在控制台输出中找特定错误：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>cat spring.log | fzf</span></span></code></pre></div><p>你可以在弹出的界面里实时过滤 <code>ERROR</code> 或 <code>Exception</code>。</p><h4 id="场景二-杀死占用的进程" tabindex="-1">场景二：杀死占用的进程 <a class="header-anchor" href="#场景二-杀死占用的进程" aria-label="Permalink to “场景二：杀死占用的进程”">​</a></h4><p>Spring Boot 端口被占了？不用再 <code>ps -ef | grep java</code> 然后手动复制 PID：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ps -ef | fzf | awk &#39;{print $2}&#39; | xargs kill -9</span></span></code></pre></div><p>直接在 <code>fzf</code> 列表里选那个 Java 进程，回车直接杀掉。</p><h4 id="场景三-配合-vim" tabindex="-1">场景三：配合 <code>vim</code> <a class="header-anchor" href="#场景三-配合-vim" aria-label="Permalink to “场景三：配合 vim”">​</a></h4><p>如果你在用 Vim 改代码，在终端输入：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>vim $(fzf)</span></span></code></pre></div><p>这会先让你选文件，选完直接进入编辑。</p><hr><h3 id="_5-进阶-预览功能-preview" tabindex="-1">5. 进阶：预览功能 (Preview) <a class="header-anchor" href="#_5-进阶-预览功能-preview" aria-label="Permalink to “5. 进阶：预览功能 (Preview)”">​</a></h3><p>这是 <code>fzf</code> 最酷炫的地方。你可以配置它在搜索时，侧边栏直接显示文件内容：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 搜索文件时，右侧显示前100行内容</span></span>
<span class="line"><span>fzf --preview &#39;cat {} | head -100&#39;</span></span></code></pre></div><p><em>提示：如果安装了 <code>bat</code>（带高亮的 cat），预览效果堪比 IDE。</em></p>`,41)])])}const g=e(r,[["render",d]]);export{f as __pageData,g as default};
